#include "flex_sensor.h"
#include <Arduino.h>
#define FLEX_PIN 34
static int _raw=0;static float _angle=0;static unsigned long _l=0;
void flex_setup(){pinMode(FLEX_PIN,INPUT);Serial.println("[flex] OK");}
void flex_loop(){if(millis()-_l<100)return;_l=millis();_raw=analogRead(FLEX_PIN);_angle=map(_raw,0,4095,0,180);}
int flex_get_raw(){return _raw;}
float flex_get_angle(){return _angle;}
